('transformer-and-llm-awareness', 'grp-deep-learning-and-specialized-modeling-awareness-foundations', 6, 'topic', NULL, NULL, NULL, 'Transformer and LLM Awareness', 'Understand transformer-based model capabilities, limitations, and evaluation concerns at a conceptual level.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "transformer-and-llm-awareness"}'::jsonb, true, true, '["Explain and apply transformer and llm awareness in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for transformer and llm awareness."]'::jsonb),
('time-series-cross-validation', 'grp-deep-learning-and-specialized-modeling-awareness-core-practice', 4, 'topic', NULL, NULL, NULL, 'Time Series Cross-Validation', 'Evaluate temporal models with forward-chaining splits and leakage-aware validation.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "time-series-cross-validation"}'::jsonb, true, true, '["Explain and apply time series cross-validation in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for time series cross-validation."]'::jsonb),
('grp-decision-delivery-and-stakeholder-evidence', 'ph-data-products-and-communication', 3, 'choice_group', NULL, 'complete_all', NULL, 'Decision Delivery and Stakeholder Evidence', 'Decision Delivery and Stakeholder Evidence adds baseline-style detail under Data Products and Communication.', 'side', NULL, NULL, '{"addedIn": "v19-depth-expansion", "nodeKey": "grp-decision-delivery-and-stakeholder-evidence"}'::jsonb, true, false, '["Decision Delivery and Stakeholder Evidence"]'::jsonb, '["Complete all required child nodes in this group."]'::jsonb),
('decision-memo-structure', 'grp-decision-delivery-and-stakeholder-evidence', 1, 'topic', NULL, NULL, NULL, 'Decision Memo Structure', 'Summarize context, evidence, assumptions, tradeoffs, recommendation, and next steps for a decision audience.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "decision-memo-structure"}'::jsonb, true, true, '["Explain and apply decision memo structure in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for decision memo structure."]'::jsonb),
('uncertainty-communication', 'grp-decision-delivery-and-stakeholder-evidence', 2, 'topic', NULL, NULL, NULL, 'Uncertainty Communication', 'Communicate uncertainty, caveats, confidence, and limitations without overstating results.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "uncertainty-communication"}'::jsonb, true, true, '["Explain and apply uncertainty communication in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for uncertainty communication."]'::jsonb),
('model-result-presentation', 'grp-decision-delivery-and-stakeholder-evidence', 3, 'topic', NULL, NULL, NULL, 'Model Result Presentation', 'Present model results with metric rationale, business implication, limitations, and actionability.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "model-result-presentation"}'::jsonb, true, true, '["Explain and apply model result presentation in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for model result presentation."]'::jsonb),
('decision-delivery-review', 'grp-decision-delivery-and-stakeholder-evidence', 4, 'checkpoint', 'assessment', NULL, NULL, 'Decision Delivery Review', 'Review checkpoint for Decision Delivery and Stakeholder Evidence. The learner synthesizes completed topics such as Decision Memo Structure, Uncertainty Communication, Model Result Presentation, records evidence, and updates the learning plan before continuing.', 'checkpoint', 2, 'intermediate', '{"reviewFocus":"Review checkpoint for Decision Delivery and Stakeholder Evidence. The learner synthesizes completed topics such as Decision Memo Structure, Uncertainty Communication, Model Result Presentation, records evidence, and updates the learning plan before continuing.","reviewCriteria":["Write a concise review of the main ideas from this segment.","Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.","Record open questions, weak areas, or follow-up actions.","Mark the checkpoint complete only after the review artifact and next steps are captured."],"nodeKey":"decision-delivery-review"}'::jsonb, true, true, '["Explain how topics from Decision Delivery and Stakeholder Evidence connect to realistic data science work.", "Select evidence that shows attempted practice, reasoning, or implementation decisions.", "Identify which topics need review before moving to later roadmap areas."]'::jsonb, '["Write a concise review of the main ideas from this segment.", "Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.", "Record open questions, weak areas, or follow-up actions.", "Mark the checkpoint complete only after the review artifact and next steps are captured."]'::jsonb),
('experiment-reproducibility-checklist', 'grp-reproducibility-ethics-and-production-awareness-foundations', 5, 'topic', NULL, NULL, NULL, 'Experiment Reproducibility Checklist', 'Track code version, data version, parameters, metrics, random seeds, and environment information.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "experiment-reproducibility-checklist"}'::jsonb, true, true, '["Explain and apply experiment reproducibility checklist in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for experiment reproducibility checklist."]'::jsonb),
('data-and-model-drift-signals', 'grp-reproducibility-ethics-and-production-awareness-foundations', 6, 'topic', NULL, NULL, NULL, 'Data and Model Drift Signals', 'Identify input drift, prediction drift, and performance drift signals for deployed data products.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "data-and-model-drift-signals"}'::jsonb, true, true, '["Explain and apply data and model drift signals in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for data and model drift signals."]'::jsonb),
('model-card-and-limitation-notes', 'grp-reproducibility-ethics-and-production-awareness-core-practice', 5, 'topic', NULL, NULL, NULL, 'Model Card and Limitation Notes', 'Document intended use, limitations, evaluation slices, fairness concerns, and monitoring expectations.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "model-card-and-limitation-notes"}'::jsonb, true, true, '["Explain and apply model card and limitation notes in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for model card and limitation notes."]'::jsonb),
('grp-capstone-evidence-and-presentation', 'ph-portfolio-capstone', 21, 'choice_group', NULL, 'complete_all', NULL, 'Capstone Evidence and Presentation', 'Capstone Evidence and Presentation adds baseline-style detail under Portfolio Capstone.', 'side', NULL, NULL, '{"addedIn": "v19-depth-expansion", "nodeKey": "grp-capstone-evidence-and-presentation"}'::jsonb, true, false, '["Capstone Evidence and Presentation"]'::jsonb, '["Complete all required child nodes in this group."]'::jsonb),
('capstone-scope-and-success-criteria', 'grp-capstone-evidence-and-presentation', 1, 'topic', NULL, NULL, NULL, 'Capstone Scope and Success Criteria', 'Define a capstone question, decision audience, deliverables, metric, and evidence checklist.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "capstone-scope-and-success-criteria"}'::jsonb, true, true, '["Explain and apply capstone scope and success criteria in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for capstone scope and success criteria."]'::jsonb),
('portfolio-narrative-and-tradeoffs', 'grp-capstone-evidence-and-presentation', 2, 'topic', NULL, NULL, NULL, 'Portfolio Narrative and Tradeoffs', 'Explain technical decisions, rejected alternatives, assumptions, and learning outcomes in a portfolio case study.', 'choice', 3, 'intermediate', '{"addedIn": "v19-depth-expansion", "nodeKey": "portfolio-narrative-and-tradeoffs"}'::jsonb, true, true, '["Explain and apply portfolio narrative and tradeoffs in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for portfolio narrative and tradeoffs."]'::jsonb),
('capstone-presentation-review', 'grp-capstone-evidence-and-presentation', 3, 'checkpoint', 'assessment', NULL, NULL, 'Capstone Presentation Review', 'Final roadmap checkpoint for Capstone Evidence and Presentation. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the data science path.', 'checkpoint', 2, 'intermediate', '{"reviewFocus":"Final roadmap checkpoint for Capstone Evidence and Presentation. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the data science path.","reviewCriteria":["Summarize completed phases, projects, and major skill groups.","Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.","List remaining gaps or specialization topics for future learning.","State that the checkpoint is a planning review, not proof of job readiness."],"nodeKey":"capstone-presentation-review"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent data science learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb);
